#include <stdio.h>

// Define the abstract syntax tree structure
typedef struct Node {
 char *value;
 struct Node *left;
 struct Node *right;
} Node;

// Generate intermediate code from the abstract syntax tree
void generateCode(Node *node) {
 if (node->left) {
 generateCode(node->left);
 }
 if (node->right) {
 generateCode(node->right);
 }
 printf("%s ", node->value);
}

int main() {
 // Create an example abstract syntax tree
 Node *root = malloc(sizeof(Node));
 root->value = "+";
 root->left = malloc(sizeof(Node));
 root->left->value = "a";
 root->right = malloc(sizeof(Node));
 root->right->value = "b * c";

 // Generate intermediate code from the abstract syntax tree
 generateCode(root);

 return 0;
}
